#include<cstdio>
#define rep(a,b,c) for(register int c=(a);c<=(b);++c)
#define grep(a,b,c) for(register int c=a.head[(b)];c;c=a.nxt[c])
inline long long Min(long long x,long long y){return x<y?x:y;}
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=3e5+10;
struct Graph
{
	int head[N],des[N],nxt[N],cnt;
	inline void ins(int x,int y){nxt[++cnt]=head[x];head[x]=cnt;des[cnt]=y;}
}a;
struct Req{int idx;long long ned;}Q[N],tmp[N];
struct Mdy{int l,r;long long val;}opt[N];
int n,m,ans[N];
long long bt[N];inline void add(int x,long long y){while(x<=m+1)bt[x]+=y,x+=(x&-x);}
inline long long qry(int x){long long res=0;while(x)res+=bt[x],x^=(x&-x);return res;}
inline void Slide(int ql,int qr,int l,int r)
{
//	printf("%d %d %d %d\n",ql,qr,l,r);
	if(l==r){rep(ql,qr,i)ans[Q[i].idx]=l;return;}
	int mid=(l+r)>>1,pl=ql-1,pr=qr+1;
	rep(l,mid,i)
	{
		opt[i].l>opt[i].r?add(1,opt[i].val):void(0);
		add(opt[i].l,opt[i].val);add(opt[i].r+1,-opt[i].val);
	}
	rep(ql,qr,i)
	{
		long long sum=0;grep(a,Q[i].idx,j)sum=Min(sum+qry(a.des[j]),Q[i].ned);
		(sum>=Q[i].ned)?(tmp[++pl]=Q[i],0):(tmp[--pr]=Q[i],tmp[pr].ned-=sum);
	}
	rep(l,mid,i)
	{
		opt[i].l>opt[i].r?add(1,-opt[i].val):void(0);
		add(opt[i].l,-opt[i].val);add(opt[i].r+1,opt[i].val);
	}
	rep(ql,qr,i)Q[i]=tmp[i];
//	printf("qwq %d %d\n",pl,pr);
	ql<=pl?Slide(ql,pl,l,mid):void(0);
	qr>=pr?Slide(pr,qr,mid+1,r):void(0);
}
int main()
{
	n=read();m=read();rep(1,m,i)a.ins(read(),i);
	rep(1,n,i)Q[i].ned=read(),Q[i].idx=i;int qq=read();
	rep(1,qq,i)opt[i].l=read(),opt[i].r=read(),opt[i].val=read();
	Slide(1,n,1,qq+1);rep(1,n,i)ans[i]<=qq?printf("%d\n",ans[i]):puts("NIE");
}
